import { describe, it, expect, vi } from "vitest";
import type { ModelMessage } from "ai";

// Test target imports
import type {
  Message,
  CheckpointMessage,
  SessionMetadata,
  CompactionConfig,
  PruningConfig,
  ContinuationVariant,
  CompactionResult,
  PreparedCompactionV2,
  ActualTokenUsage,
  ActualTokenUsageInput,
  ContextUsage,
  TodoItem,
  StructuredState,
  SessionHeaderLine,
  MessageLine,
  CheckpointLine,
  SessionFileLine,
  CompactionSummary,
  CompactionSegment,
  PreparedCompactionSegment,
  PreparedCompaction,
} from "./compaction-types";

describe("Message Interface", () => {
  it("should have required fields: createdAt, id, modelMessage", () => {
    const validMessage: Message = {
      createdAt: new Date(),
      id: "msg-123",
      modelMessage: { role: "user", content: "Hello" },
    };
    expect(validMessage.createdAt).toBeInstanceOf(Date);
    expect(validMessage.id).toBe("msg-123");
    expect(validMessage.modelMessage).toBeDefined();
  });

  it("should allow optional originalContent field", () => {
    const messageWithoutOriginal: Message = {
      createdAt: new Date(),
      id: "msg-123",
      modelMessage: { role: "user", content: "Hello" },
    };
    expect(messageWithoutOriginal.originalContent).toBeUndefined();

    const messageWithOriginal: Message = {
      createdAt: new Date(),
      id: "msg-123",
      modelMessage: { role: "user", content: "Hello" },
      originalContent: "Original text",
    };
    expect(messageWithOriginal.originalContent).toBe("Original text");
  });

  it("should be compatible with CheckpointMessage type", () => {
    // Message should be assignable where Message type is expected
    const checkpointMsg: Message = {
      createdAt: new Date("2024-01-01"),
      id: "msg-456",
      modelMessage: { role: "assistant", content: "Response" },
    };
    expect(checkpointMsg.createdAt).toEqual(new Date("2024-01-01"));
  });
});

describe("CheckpointMessage Interface", () => {
  it("should have all required fields", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "checkpoint-123",
      isSummary: false,
      message: { role: "user", content: "Test" },
    };
    expect(checkpoint.createdAt).toBeDefined();
    expect(checkpoint.id).toBeDefined();
    expect(checkpoint.isSummary).toBe(false);
    expect(checkpoint.message).toBeDefined();
  });

  it("should allow optional isSummaryMessage field", () => {
    const withoutOptional: CheckpointMessage = {
      createdAt: Date.now(),
      id: "cp-1",
      isSummary: false,
      message: { role: "user", content: "Test" },
    };
    expect(withoutOptional.isSummaryMessage).toBeUndefined();

    const withOptional: CheckpointMessage = {
      createdAt: Date.now(),
      id: "cp-2",
      isSummary: false,
      message: { role: "user", content: "Test" },
      isSummaryMessage: true,
    };
    expect(withOptional.isSummaryMessage).toBe(true);
  });

  it("should allow optional originalContent field", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "cp-3",
      isSummary: true,
      message: { role: "assistant", content: "Summary" },
      originalContent: "Original content before rewrite",
    };
    expect(checkpoint.originalContent).toBe("Original content before rewrite");
  });

  it("should require isSummary to be boolean", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "cp-4",
      isSummary: true,
      message: { role: "user", content: "Test" },
    };
    expect(typeof checkpoint.isSummary).toBe("boolean");
  });
});

describe("SessionMetadata Interface", () => {
  it("should have all required fields with correct types", () => {
    const metadata: SessionMetadata = {
      completionTokens: 100,
      createdAt: Date.now(),
      promptTokens: 50,
      sessionId: "session-123",
      summaryMessageId: null,
      updatedAt: Date.now(),
    };
    expect(typeof metadata.completionTokens).toBe("number");
    expect(typeof metadata.createdAt).toBe("number");
    expect(typeof metadata.promptTokens).toBe("number");
    expect(typeof metadata.sessionId).toBe("string");
    expect(metadata.summaryMessageId).toBeNull();
    expect(typeof metadata.updatedAt).toBe("number");
  });

  it("should allow summaryMessageId to be a string after compaction", () => {
    const metadata: SessionMetadata = {
      completionTokens: 200,
      createdAt: Date.now(),
      promptTokens: 100,
      sessionId: "session-456",
      summaryMessageId: "summary-msg-789",
      updatedAt: Date.now(),
    };
    expect(typeof metadata.summaryMessageId).toBe("string");
  });

  it("should not allow undefined for required numeric fields", () => {
    // These should cause TypeScript errors if uncommented:
    // const invalid: SessionMetadata = { sessionId: "test" }; // missing required fields
    // expect(() => invalid.completionTokens).toThrow();
    expect(true).toBe(true); // Placeholder - TypeScript prevents this at compile time
  });
});

describe("CompactionConfig Interface", () => {
  const defaultConfig: CompactionConfig = {};

  it("should have all optional fields", () => {
    expect(defaultConfig.contextLimit).toBeUndefined();
    expect(defaultConfig.enabled).toBeUndefined();
    expect(defaultConfig.getStructuredState).toBeUndefined();
    expect(defaultConfig.keepRecentTokens).toBeUndefined();
    expect(defaultConfig.maxTokens).toBeUndefined();
    expect(defaultConfig.reserveTokens).toBeUndefined();
    expect(defaultConfig.speculativeStartRatio).toBeUndefined();
    expect(defaultConfig.summarizeFn).toBeUndefined();
    expect(defaultConfig.thresholdRatio).toBeUndefined();
  });

  it("should accept valid contextLimit values", () => {
    const config: CompactionConfig = { contextLimit: 128000 };
    expect(config.contextLimit).toBe(128000);

    const unlimited: CompactionConfig = { contextLimit: 0 };
    expect(unlimited.contextLimit).toBe(0);

    const unlimitedByUndefined: CompactionConfig = { contextLimit: undefined };
    expect(unlimitedByUndefined.contextLimit).toBeUndefined();
  });

  it("should accept enabled boolean", () => {
    const config: CompactionConfig = { enabled: true };
    expect(config.enabled).toBe(true);

    const disabled: CompactionConfig = { enabled: false };
    expect(disabled.enabled).toBe(false);
  });

  it("should accept getStructuredState callback", () => {
    const getState = vi.fn(() => "<structured-state>test</structured-state>");
    const config: CompactionConfig = { getStructuredState: getState };
    expect(config.getStructuredState).toBeDefined();
    expect(typeof config.getStructuredState).toBe("function");
  });

  it("should accept keepRecentTokens with default value 2000", () => {
    const config: CompactionConfig = { keepRecentTokens: 2000 };
    expect(config.keepRecentTokens).toBe(2000);

    const zeroKeep: CompactionConfig = { keepRecentTokens: 0 };
    expect(zeroKeep.keepRecentTokens).toBe(0);
  });

  it("should accept maxTokens with default value 8000", () => {
    const config: CompactionConfig = { maxTokens: 8000 };
    expect(config.maxTokens).toBe(8000);
  });

  it("should accept reserveTokens with default value 2000", () => {
    const config: CompactionConfig = { reserveTokens: 2000 };
    expect(config.reserveTokens).toBe(2000);
  });

  it("should accept speculativeStartRatio with valid range", () => {
    const config: CompactionConfig = { speculativeStartRatio: 0.5 };
    expect(config.speculativeStartRatio).toBe(0.5);

    const minRatio: CompactionConfig = { speculativeStartRatio: 0.15 };
    expect(minRatio.speculativeStartRatio).toBe(0.15);

    const maxRatio: CompactionConfig = { speculativeStartRatio: 0.95 };
    expect(maxRatio.speculativeStartRatio).toBe(0.95);
  });

  it("should accept summarizeFn callback", () => {
    const summarizeFn = vi.fn(
      async (messages: ModelMessage[], previousSummary?: string) => {
        return "Summary text";
      }
    );
    const config: CompactionConfig = { summarizeFn };
    expect(config.summarizeFn).toBeDefined();
  });

  it("should accept thresholdRatio with default 0.5", () => {
    const config: CompactionConfig = { thresholdRatio: 0.5 };
    expect(config.thresholdRatio).toBe(0.5);

    const zeroThreshold: CompactionConfig = { thresholdRatio: 0 };
    expect(zeroThreshold.thresholdRatio).toBe(0);

    const fullThreshold: CompactionConfig = { thresholdRatio: 1 };
    expect(fullThreshold.thresholdRatio).toBe(1);
  });

  it("should allow multiple config options together", () => {
    const config: CompactionConfig = {
      contextLimit: 128000,
      enabled: true,
      keepRecentTokens: 2000,
      maxTokens: 8000,
      reserveTokens: 2000,
      speculativeStartRatio: 0.5,
      thresholdRatio: 0.5,
    };
    expect(config.contextLimit).toBe(128000);
    expect(config.enabled).toBe(true);
    expect(config.keepRecentTokens).toBe(2000);
    expect(config.maxTokens).toBe(8000);
  });
});

describe("PruningConfig Interface", () => {
  it("should have all optional fields with correct defaults", () => {
    const defaultPruning: PruningConfig = {};
    expect(defaultPruning.enabled).toBeUndefined();
    expect(defaultPruning.minSavingsTokens).toBeUndefined();
    expect(defaultPruning.protectedToolNames).toBeUndefined();
    expect(defaultPruning.protectRecentTokens).toBeUndefined();
    expect(defaultPruning.replacementText).toBeUndefined();
  });

  it("should accept enabled field", () => {
    const config: PruningConfig = { enabled: true };
    expect(config.enabled).toBe(true);
  });

  it("should accept minSavingsTokens with default 200", () => {
    const config: PruningConfig = { minSavingsTokens: 200 };
    expect(config.minSavingsTokens).toBe(200);
  });

  it("should accept protectedToolNames array", () => {
    const config: PruningConfig = {
      protectedToolNames: ["tool1", "tool2", "tool3"],
    };
    expect(config.protectedToolNames).toHaveLength(3);
    expect(config.protectedToolNames).toContain("tool1");
  });

  it("should accept protectRecentTokens with default 2000", () => {
    const config: PruningConfig = { protectRecentTokens: 2000 };
    expect(config.protectRecentTokens).toBe(2000);
  });

  it("should accept replacementText with default value", () => {
    const config: PruningConfig = {
      replacementText: "[output pruned — too large]",
    };
    expect(config.replacementText).toBe("[output pruned — too large]");
  });
});

describe("ContinuationVariant Type", () => {
  it("should accept 'manual' variant", () => {
    const variant: ContinuationVariant = "manual";
    expect(variant).toBe("manual");
  });

  it("should accept 'auto-with-replay' variant", () => {
    const variant: ContinuationVariant = "auto-with-replay";
    expect(variant).toBe("auto-with-replay");
  });

  it("should accept 'tool-loop' variant", () => {
    const variant: ContinuationVariant = "tool-loop";
    expect(variant).toBe("tool-loop");
  });

  it("should not accept invalid variants", () => {
    // TypeScript compile-time check - these would cause errors:
    // const invalid: ContinuationVariant = "invalid";
    // const invalid2: ContinuationVariant = "auto";
    expect(true).toBe(true); // Placeholder - TypeScript prevents this at compile time
  });

  it("should work with union type patterns", () => {
    const variants: ContinuationVariant[] = [
      "manual",
      "auto-with-replay",
      "tool-loop",
    ];
    expect(variants).toHaveLength(3);
  });
});

describe("CompactionResult Interface", () => {
  it("should have required success field", () => {
    const result: CompactionResult = {
      success: true,
      tokensBefore: 1000,
      tokensAfter: 500,
    };
    expect(result.success).toBe(true);
  });

  it("should allow optional fields", () => {
    const result: CompactionResult = {
      success: false,
      tokensBefore: 1000,
      tokensAfter: 800,
      reason: "Threshold not reached",
    };
    expect(result.reason).toBe("Threshold not reached");

    const successResult: CompactionResult = {
      success: true,
      tokensBefore: 1000,
      tokensAfter: 400,
      summaryMessageId: "summary-123",
      continuationVariant: "auto-with-replay",
    };
    expect(successResult.summaryMessageId).toBe("summary-123");
    expect(successResult.continuationVariant).toBe("auto-with-replay");
  });

  it("should track token changes", () => {
    const result: CompactionResult = {
      success: true,
      tokensBefore: 8000,
      tokensAfter: 3000,
    };
    expect(result.tokensBefore).toBeGreaterThan(result.tokensAfter);
